// test_sha1.cpp - Unit tests for SHA-1 computation
// Tests sha1_compute() against NIST FIPS 180-1 test vectors

#include "test_harness.h"

// ============================================================================
// SHA-1 NIST Test Vectors
// ============================================================================

// Test vector: empty string
// SHA-1("") = da39a3ee5e6b4b0d3255bfef95601890afd80709
TEST(sha1_empty_string) {
    uint8_t result[20];
    sha1_compute("", 0, result);

    uint8_t expected[20] = {
        0xda, 0x39, 0xa3, 0xee, 0x5e, 0x6b, 0x4b, 0x0d,
        0x32, 0x55, 0xbf, 0xef, 0x95, 0x60, 0x18, 0x90,
        0xaf, 0xd8, 0x07, 0x09
    };

    TEST_ASSERT_MEMEQ(result, expected, 20);
}

// Test vector: "a"
// SHA-1("a") = 86f7e437faa5a7fce15d1ddcb9eaeaea377667b8
TEST(sha1_single_char_a) {
    uint8_t result[20];
    sha1_compute("a", 1, result);

    uint8_t expected[20] = {
        0x86, 0xf7, 0xe4, 0x37, 0xfa, 0xa5, 0xa7, 0xfc,
        0xe1, 0x5d, 0x1d, 0xdc, 0xb9, 0xea, 0xea, 0xea,
        0x37, 0x76, 0x67, 0xb8
    };

    TEST_ASSERT_MEMEQ(result, expected, 20);
}

// Test vector: "abc"
// SHA-1("abc") = a9993e364706816aba3e25717850c26c9cd0d89d
TEST(sha1_abc) {
    uint8_t result[20];
    sha1_compute("abc", 3, result);

    uint8_t expected[20] = {
        0xa9, 0x99, 0x3e, 0x36, 0x47, 0x06, 0x81, 0x6a,
        0xba, 0x3e, 0x25, 0x71, 0x78, 0x50, 0xc2, 0x6c,
        0x9c, 0xd0, 0xd8, 0x9d
    };

    TEST_ASSERT_MEMEQ(result, expected, 20);
}

// Test vector: "message digest"
// Computed by our implementation (NIST vectors abc/448-bit/quick-fox all pass)
TEST(sha1_message_digest) {
    const char* input = "message digest";
    uint8_t result[20];
    sha1_compute(input, strlen(input), result);

    // Verify deterministic output
    char hex[41];
    sha1_to_hex(result, hex);
    TEST_ASSERT_STREQ(hex, "c12252ceda8be8994d5fa0290a47231c1d16aae3");
}

// Test vector: "abcdefghijklmnopqrstuvwxyz"
// SHA-1("abcdefghijklmnopqrstuvwxyz") = 32d10c7b8cf96570ca04ce37f2a19d84240d3a89
TEST(sha1_alphabet) {
    const char* input = "abcdefghijklmnopqrstuvwxyz";
    uint8_t result[20];
    sha1_compute(input, strlen(input), result);

    uint8_t expected[20] = {
        0x32, 0xd1, 0x0c, 0x7b, 0x8c, 0xf9, 0x65, 0x70,
        0xca, 0x04, 0xce, 0x37, 0xf2, 0xa1, 0x9d, 0x84,
        0x24, 0x0d, 0x3a, 0x89
    };

    TEST_ASSERT_MEMEQ(result, expected, 20);
}

// Test vector: 448 bits (exactly one block minus length field)
// "abcdbcdecdefdefgefghfghighijhijkijkljklmklmnlmnomnopnopq"
// SHA-1 = 84983e441c3bd26ebaae4aa1f95129e5e54670f1
TEST(sha1_448_bits) {
    const char* input = "abcdbcdecdefdefgefghfghighijhijkijkljklmklmnlmnomnopnopq";
    uint8_t result[20];
    sha1_compute(input, strlen(input), result);

    uint8_t expected[20] = {
        0x84, 0x98, 0x3e, 0x44, 0x1c, 0x3b, 0xd2, 0x6e,
        0xba, 0xae, 0x4a, 0xa1, 0xf9, 0x51, 0x29, 0xe5,
        0xe5, 0x46, 0x70, 0xf1
    };

    TEST_ASSERT_MEMEQ(result, expected, 20);
}

// Test: Multi-block message (longer than 64 bytes)
// SHA-1("The quick brown fox jumps over the lazy dog") = 2fd4e1c67a2d28fced849ee1bb76e7391b93eb12
TEST(sha1_quick_brown_fox) {
    const char* input = "The quick brown fox jumps over the lazy dog";
    uint8_t result[20];
    sha1_compute(input, strlen(input), result);

    uint8_t expected[20] = {
        0x2f, 0xd4, 0xe1, 0xc6, 0x7a, 0x2d, 0x28, 0xfc,
        0xed, 0x84, 0x9e, 0xe1, 0xbb, 0x76, 0xe7, 0x39,
        0x1b, 0x93, 0xeb, 0x12
    };

    TEST_ASSERT_MEMEQ(result, expected, 20);
}

// Test: Git blob header format
// Git blob object: "blob <size>\0<content>"
// This tests the format git uses for computing blob SHAs
TEST(sha1_git_blob_format) {
    // For content "hello\n", git computes: ce013625030ba8dba906f756967f9e9ca394464a
    // Header is "blob 6\0" + "hello\n"
    char blob_obj[14] = "blob 6\0hello\n";
    uint8_t result[20];
    sha1_compute(blob_obj, 13, result);  // 7 header + 6 content

    char hex[41];
    sha1_to_hex(result, hex);

    TEST_ASSERT_STREQ(hex, "ce013625030ba8dba906f756967f9e9ca394464a");
}

// Test: Exactly 55 bytes (boundary case - fits in single block with padding)
TEST(sha1_55_bytes) {
    char input[56];
    for (int i = 0; i < 55; i++) input[i] = 'a';
    input[55] = '\0';

    uint8_t result[20];
    sha1_compute(input, 55, result);

    // Verify it completes without crash and produces valid output
    char hex[41];
    sha1_to_hex(result, hex);
    TEST_ASSERT_EQ(strlen(hex), 40);
}

// Test: Exactly 56 bytes (boundary case - requires two blocks)
TEST(sha1_56_bytes) {
    char input[57];
    for (int i = 0; i < 56; i++) input[i] = 'a';
    input[56] = '\0';

    uint8_t result[20];
    sha1_compute(input, 56, result);

    // Verify it completes without crash and produces valid output
    char hex[41];
    sha1_to_hex(result, hex);
    TEST_ASSERT_EQ(strlen(hex), 40);
}

// Test: Exactly 64 bytes (one full block)
TEST(sha1_64_bytes) {
    char input[65];
    for (int i = 0; i < 64; i++) input[i] = 'a';
    input[64] = '\0';

    uint8_t result[20];
    sha1_compute(input, 64, result);

    char hex[41];
    sha1_to_hex(result, hex);
    TEST_ASSERT_EQ(strlen(hex), 40);
}

// Test: Binary data (with null bytes embedded)
TEST(sha1_binary_data) {
    uint8_t binary[] = { 0x00, 0x01, 0x02, 0x00, 0xFF, 0xFE, 0x00, 0x03 };
    uint8_t result[20];
    sha1_compute(binary, sizeof(binary), result);

    // Just verify it produces valid output without crashing on nulls
    char hex[41];
    sha1_to_hex(result, hex);
    TEST_ASSERT_EQ(strlen(hex), 40);
}

// Test: Determinism - same input always produces same output
TEST(sha1_deterministic) {
    const char* input = "test determinism";
    uint8_t result1[20], result2[20];

    sha1_compute(input, strlen(input), result1);
    sha1_compute(input, strlen(input), result2);

    TEST_ASSERT_MEMEQ(result1, result2, 20);
}
